int* calculate_fibfib_numbers(int n, int* indices, int size, int* result_size) {
    // Allocate memory for the fibfib sequence up to n
    // malloc is used for dynamic memory allocation on the heap
    int* fibfib = (int*) malloc((n + 1) * sizeof(int)); 
    if (fibfib == NULL) return NULL;

    fibfib[0] = 0;
    fibfib[1] = 0;
    fibfib[2] = 1;

