content = """
def factorial(n):
    if n == 0:
        return 1
    else:
        return n * factorial(n-1)

def check_if_factorial(input_number):
    n = 0
    while factorial(n) <= input_number:
        if factorial(n) == input_number:
            return True
        n += 1
    return False

input_val = 24
if check_if_factorial(input_val):
    print(f"The number {input_val} can be expressed as a factorial.")
else:
    print(f"The number {input_val} can't be expressed as a factorial.")
"""
