code = "import time
import random

def counting_sort(array, digit):
    size = len(array)
    output = [0] * size
    count = [0] * 10

    for i in range(0, size):
        index = int(array[i] / digit)
        count[index % 10] += 1

    for i in range(1, 10):
        count[i] += count[i - 1]

    i = size - 1
    while i >= 0:
        index = int(array[i] / digit)
        output[count[index % 10] - 1] = array[i]
        count[index % 10] -= 1
        i -= 1

    for i in range(0, size):
        array[i] = output[i]

def radix_sort(array):
    if not array:
        return array
    max_val = max(array)
    exp = 1
    while max_val // exp > 0:
        counting_sort(array, exp)
        exp *= 10
    return array

def benchmark(sort_func, data):
    start = time.time()
    sort_func(data.copy())
    return time.time() - start

