content = "# Load necessary libraries
library(tidyverse)
library(caret)
library(randomForest)
library(cluster)

# 1. Data Loading and Preprocessing
process_data <- function(filepath) {
  data <- read.csv(filepath)

  # Handling missing values: Median imputation for numeric, Mode for categorical
  for(i in 1:ncol(data)) {
    if(is.numeric(data[[i]])) {
      data[[i]][is.na(data[[i]])] <- median(data[[i]], na.rm = TRUE)
    } else {
      # Simple mode imputation
      mode_val <- names(sort(table(data[[i]]), decreasing = TRUE))[1]
      data[[i]][is.na(data[[i]])] <- mode_val
    }
  }

  # Outlier handling: Capping at 1.5 * IQR
  cap_outliers <- function(x) {
    qnt <- quantile(x, probs=c(.25, .75), na.rm = TRUE)
    caps <- quantile(x, probs=c(.05, .95), na.rm = TRUE)
    H <- 1.5 * IQR(x, na.rm = TRUE)
    x[x < (qnt[1] - H)] <- caps[1]
    x[x > (qnt[2] + H)] <- caps[2]
    return(x)
  }
  numeric_cols <- sapply(data, is.numeric)
  data[numeric_cols] <- lapply(data[numeric_cols], cap_outliers)

  return(data)
}

# 2. Dimensionality Reduction
reduce_dims <- function(data) {
  numeric_data <- data[sapply(data, is.numeric)]
  pca_res <- prcomp(numeric_data, center = TRUE, scale = TRUE)
  # Keep components explaining 95% variance
  var_explained <- cumsum(pca_res$sdev^2) / sum(pca_res$sdev^2)
  num_comp <- which(var_explained >= 0.95)[1]
  return(pca_res[, 1:num_comp])
}

# 3. Unsupervised Learning (Clustering)
perform_clustering <- function(pca_data, k=3) {
  clusters <- kmeans(pca_data, centers = k, iter.max = 100, nstart = 25)
  return(clusters$cluster)
}

# 4. Supervised Learning (Prediction)
predict_sleep_quality <- function(original_data, cluster_labels) {
  # Add clusters as a feature
  original_data$Cluster <- as.factor(cluster_labels)

  # Split data
  set.seed(123)
  trainIndex <- createDataPartition(original_data$SleepQuality, p = .8, list = FALSE)
  train_set <- original_data[trainIndex, ]
  test_set <- original_data[-trainIndex, ]

  # Random Forest Model
  rf_model <- randomForest(SleepQuality ~ ., data = train_set, na.action = na.exclude)

  # Prediction and Accuracy
  preds <- predict(rf_model, test_set)
  acc <- postResample(preds, test_set$SleepQuality)

  return(list(model = rf_model, accuracy = acc))
}

# Main Execution Pipeline
main <- function(file) {
  df <- process_data(file)
  pca_df <- reduce_dims(df)
  clusters <- perform_clustering(pca_df)
  results <- predict_sleep_quality(df, clusters)

  print(paste('Model Accuracy:', results$accuracy))
  return(results)
}
"
