Thought: I need to implement a 3-way merge sort in Java. I will write the code to a file named `ThreeWayMergeSort.java`, including the merge logic, the recursive sort, and a method to reverse the array. I'll then verify it by compiling and running it with a test case.
<code>
code = """public class ThreeWayMergeSort {

    public static void sort(int[] arr) {
        int[] temp = new int[arr.length];
        mergeSort(arr, 0, arr.length, temp);
    }

    private static void mergeSort(int[] arr, int start, int end, int[] temp) {
        if (end - start <= 1) return;

        int mid1 = start + (end - start) / 3;
        int mid2 = start + 2 * (end - start) / 3;

        mergeSort(arr, start, mid1, temp);
        mergeSort(arr, mid1, mid2, temp);
        mergeSort(arr, mid2, end, temp);

        merge(arr, start, mid1, mid2, end, temp);
        System.arraycopy(temp, start, arr, start, end - start);
    }

    private static void merge(int[] arr, int start, int mid1, int mid2, int end, int[] temp) {
        int i = start, j = mid1, k = mid2, l = start;

        while (i < mid1 && j < mid2 && k < end) {
            if (arr[i] < arr[j]) {
                if (arr[i] < arr[k]) temp[l++] = arr[i++];
                else temp[l++] = arr[k++];
            } else {
                if (arr[j] < arr[k]) temp[l++] = arr[j++];
                else temp[l++] = arr[k++];
            }
        }

        while (i < mid1 && j < mid2) {
            if (arr[i] < arr[j]) temp[l++] = arr[i++];
            else temp[l++] = arr[j++];
        }

        while (j < mid2 && k < end) {
            if (arr[j] < arr[k]) temp[l++] = arr[j++];
            else temp[l++] = arr[k++];
        }

        while (i < mid1 && k < end) {
            if (arr[i] < arr[k]) temp[l++] = arr[i++];
            else temp[l++] = arr[k++];
        }

        while (i < mid1) temp[l++] = arr[i++];
        while (j < mid2) temp[l++] = arr[j++];
        while (k < end) temp[l++] = arr[k++];
    }

    public static void reverse(int[] arr) {
        int left = 0, right = arr.length - 1;
        while (left < right) {
            int temp = arr[left];
            arr[left] = arr[right];
            arr[right] = temp;
            left++;
            right--;
        }
    }

    public static void main(String[] args) {
        int[] arr = {12, 11, 13, 5, 6, 7, 3, 1, 15};
        sort(arr);
        for (int i : arr) System.out.print(i + " ");
        System.out.println();
        reverse(arr);
        for (int i : arr) System.out.print(i + " ");
    }
}"""
