function validateString(s) {
    // Regex to check if string contains at least one special character
    var regex = /(.*[!@#$%^&*()].*){1,}/;

    // Check for special character presence and minimum length of 8
    if (regex.test(s) && s.length >= 8) {
        // Split by any non-digit character to isolate groups of digits
        var splitArr = s.split(/[^0-9]/);
        for(let i = 0; i < splitArr.length; i++) {
            // If any group of digits is longer than 3, it violates the requirement
            if(splitArr[i].length > 3) return false;
        }
        return true;
    }

    return false;
}

