content = "import sqlite3
from sqlite3 import Error
from contextlib import closing

class SimpleDB:
    def __init__(self, db_file):
        self.db_file = db_file

    def execute(self, query, params=(), commit=False):
        # Using closing to ensure connection is closed, simulating basic pooling
        with closing(sqlite3.connect(self.db_file, detect_types=sqlite3.PARSE_DECLTYPES)) as conn:
            try:
                cur = conn.cursor()
                cur.execute(query, params)
                if commit:
                    conn.commit()
                    return cur.rowcount
                return cur.fetchall()
            except Error as e:
                conn.rollback()
                raise e

    def create(self, table, **kwargs):
        columns = ', '.join(kwargs.keys())
        placeholders = ', '.join(['?' for _ in kwargs])
        query = f'INSERT INTO {table} ({columns}) VALUES ({placeholders})'
        # To return the last inserted ID, we need a slightly different execute approach
        with closing(sqlite3.connect(self.db_file)) as conn:
            try:
                cur = conn.cursor()
                cur.execute(query, tuple(kwargs.values()))
                conn.commit()
                return cur.lastrowid
            except Error as e:
                conn.rollback()
                raise e

    def read(self, table, order=None, filter_clause=None, page=None, limit=10):
        query = f'SELECT * FROM {table}'
        if filter_clause:
            query += f" WHERE {filter_clause}"
        if order:
            query += f" ORDER BY {order}"
        if page is not None:
            offset = (page - 1) * limit
            query += f" LIMIT {limit} OFFSET {offset}"
        return self.execute(query)

    def update(self, table, conditions, **kwargs):
        set_clause = ', '.join([f"{key}=?" for key in kwargs])
        query = f'UPDATE {table} SET {set_clause} WHERE {conditions}'
        return self.execute(query, tuple(kwargs.values()), True)

    def delete(self, table, conditions):
        query = f'DELETE FROM {table} WHERE {conditions}'
        return self.execute(query, (), True)

    def complex_query(self, query, params=()):
        return self.execute(query, params)
"
