Thought: To solve this, I need to implement a Red-Black Tree that is augmented with subtree sizes. This allows us to find the kth largest element in O(log n) time. I will write a Python implementation to demonstrate this methodology, including the augmentation logic and the search algorithm.
<code>
content = """
class Node:
    def __init__(self, val, color='RED'):
        self.val = val
        self.color = color
        self.left = None
        self.right = None
        self.parent = None
        self.size = 1

class RedBlackTree:
    def __init__(self):
        self.NIL = Node(None, color='BLACK')
        self.NIL.size = 0
        self.root = self.NIL

    def update_size(self, x):
        if x != self.NIL:
            x.size = x.left.size + x.right.size + 1

    def rotate_left(self, x):
        y = x.right
        x.right = y.left
        if y.left != self.NIL:
            y.left.parent = x
        y.parent = x.parent
        if x.parent == None:
            self.root = y
        elif x == x.parent.left:
            x.parent.left = y
        else:
            x.parent.right = y
        y.left = x
        x.parent = y
        self.update_size(x)
        self.update_size(y)

    def rotate_right(self, x):
        y = x.left
        x.left = y.right
        if y.right != self.NIL:
            y.right.parent = x
        y.parent = x.parent
        if x.parent == None:
            self.root = y
        elif x == x.parent.right:
            x.parent.right = y
        else:
            x.parent.left = y
        y.right = x
        x.parent = y
        self.update_size(x)
        self.update_size(y)

    def insert(self, key):
        z = Node(key)
        z.left = self.NIL
        z.right = self.NIL

        y = None
        x = self.root
        while x != self.NIL:
            y = x
            x.size += 1 # Increment size along path
            if z.val < x.val:
                x = x.left
            else:
                x = x.right

        z.parent = y
        if y == None:
            self.root = z
        elif z.val < y.val:
            y.left = z
        else:
            y.right = z

        # Normally RB-Tree fixup would go here. 
        # For the sake of the methodology demo, we focus on the size augmentation.
        # In a full implementation, rotations in fixup would call update_size.

    def find_kth_largest(self, k):
        # The kth largest is the (N - k + 1)th smallest
        # Or we can traverse based on right-subtree size
        return self._find_kth_largest_rec(self.root, k)

    def _find_kth_largest_rec(self, node, k):
        if node == self.NIL:
            return None

        # Number of nodes in the right subtree
        right_size = node.right.size

        if k == right_size + 1:
            return node.val
        elif k <= right_size:
            return self._find_kth_largest_rec(node.right, k)
        else:
            return self._find_kth_largest_rec(node.left, k - right_size - 1)

# Test the methodology
rbt = RedBlackTree()
for val in [10, 20, 30, 15, 25, 5, 1]:
    rbt.insert(val)

# Sorted: 1, 5, 10, 15, 20, 25, 30
# 1st largest: 30, 2nd: 25, 3rd: 20, 4th: 15...
